document.addEventListener('DOMContentLoaded', () => {
 const container = document.getElementById('avis-container');
 if (!container) return;
 const defaults = [
 { name: 'Sophie M.', note: 5, text: 'Bijoux magnifiques, la qualité est au rendez-vous. Le pendentif est encore plus beau en vrai !', date: '2026-06-15' },
 { name: 'Thomas L.', note: 5, text: 'Livraison rapide et soignée. Le bracelet bouddha en cuir est superbe, je le porte tous les jours.', date: '2026-06-20' },
 { name: 'Marie K.', note: 5, text: 'Je recommande vivement ! Les pierres sont authentiques et les explications sur chaque chakra sont très claires.', date: '2026-07-01' },
 { name: 'Lucas P.', note: 4, text: 'Très belle boutique spirituelle. L\'amulette que j\'ai commandée correspond parfaitement à la description.', date: '2026-07-05' },
 ];
 const stored = JSON.parse(localStorage.getItem('bouddhas_avis') || '[]');
 const allAvis = [...stored, ...defaults];
 if (allAvis.length === 0) {
 container.innerHTML = '<p style="text-align:center;color:var(--text-light);">Soyez le premier à donner votre avis !</p>';
 return;
 }
 container.innerHTML = `
 <div class="avis-grid">
 ${allAvis.map(a => `
 <div class="avis-card">
 <div class="avis-etoiles">${'★'.repeat(a.note)}${'☆'.repeat(5 - a.note)}</div>
 <p class="avis-texte">${a.text}</p>
 <div style="display:flex;justify-content:space-between;color:var(--text-light);font-size:0.85rem;margin-top:0.5rem;">
 <span>— ${a.name}</span>
 <span>${a.date}</span>
 </div>
 </div>
 `).join('')}
 </div>
 `;
});